# SQL
# ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

SQL_INSERT = text("""
    INSERT INTO software_registry
        (id, name, slug, registry, description, trust_score, trust_grade,
         enriched_at, created_at, is_king)
    VALUES
        (:id, :name, :slug, :registry, :desc, :score, :grade,
         NOW(), NOW(), :is_king)
    ON CONFLICT (registry, slug) DO NOTHING
""")

SQL_INSERT_ALIAS = text("""
    INSERT INTO software_registry
        (id, name, slug, registry, description, trust_score, trust_grade,
         enriched_at, created_at, is_king)
    VALUES
        (:id, :name, :slug, :registry, :desc, :score, :grade,
         NOW(), NOW(), :is_king)
    ON CONFLICT (registry, slug) DO NOTHING
""")

SQL_CHECK_SLUG = text("""
    SELECT 1 FROM software_registry WHERE slug = :slug LIMIT 1
""")


def seed():
    """Insert all supplement and cosmetic_ingredient entities (skip existing)."""
    session = get_session()
    total = 0
    batch = 0
    skipped = 0

    # ── 1. Supplements ───────────────────────────────────────────────────────
    log.info("Seeding supplements...")
    for name, slug, score, is_king, desc in SUPPLEMENTS:
        grade = _grade(score)
        session.execute(SQL_INSERT, {
            "id": str(uuid4()), "name": name, "slug": slug,
            "registry": "supplement", "desc": desc, "score": score,
            "grade": grade, "is_king": is_king,
        })
        total += 1
        batch += 1
        if batch >= 200:
            session.commit()
            log.info(f"  Committed batch ({total} so far)")
            batch = 0

    log.info(f"  Supplements done: {len(SUPPLEMENTS)}")

    # ── 2. Cosmetic Ingredients ──────────────────────────────────────────────
    log.info("Seeding cosmetic ingredients...")
    for name, slug, score, is_king, desc in COSMETICS:
        grade = _grade(score)
        session.execute(SQL_INSERT, {
            "id": str(uuid4()), "name": name, "slug": slug,
            "registry": "cosmetic_ingredient", "desc": desc, "score": score,
            "grade": grade, "is_king": is_king,
        })
        total += 1
        batch += 1
        if batch >= 200:
            session.commit()
            log.info(f"  Committed batch ({total} so far)")
            batch = 0

    # Commit remaining
    if batch > 0:
        session.commit()
        batch = 0

    log.info(f"  Cosmetics done: {len(COSMETICS)}")
    log.info(f"Total entities inserted (or skipped if existing): {total}")

    # ── 3. Natural slug aliases ──────────────────────────────────────────────
    log.info("Creating natural slug aliases...")
    alias_count = 0
    all_entities = [(s, "supplement") for s in SUPPLEMENTS] + [(c, "cosmetic_ingredient") for c in COSMETICS]

    for (name, slug, score, is_king, desc), registry in all_entities:
        # Check for -supplement or -cosmetic suffix
        natural_slug = None
        if slug.endswith("-supplement"):
            natural_slug = slug.rsplit("-supplement", 1)[0]
        elif slug.endswith("-cosmetic"):
            natural_slug = slug.rsplit("-cosmetic", 1)[0]

        if not natural_slug:
            continue

        # Check if natural slug already exists (any registry)
        exists = session.execute(SQL_CHECK_SLUG, {"slug": natural_slug}).fetchone()
        if exists:
            continue

        grade = _grade(score)
        session.execute(SQL_INSERT_ALIAS, {
            "id": str(uuid4()), "name": name, "slug": natural_slug,
            "registry": registry, "desc": desc, "score": score,
            "grade": grade, "is_king": is_king,
        })
        alias_count += 1
        batch += 1
        if batch >= 200:
            session.commit()
            log.info(f"  Committed alias batch ({alias_count} aliases so far)")
            batch = 0

    if batch > 0:
        session.commit()

    session.close()
    log.info(f"Alias creation complete: {alias_count} natural slug aliases created")
    log.info(f"═══════════════════════════════════════════════════")
    log.info(f"  Supplements:         {len(SUPPLEMENTS)}")
    log.info(f"  Cosmetic ingredients: {len(COSMETICS)}")
    log.info(f"  Natural slug aliases: {alias_count}")
    log.info(f"  Grand total:         {total} + {alias_count} aliases")
    log.info(f"═══════════════════════════════════════════════════")


if __name__ == "__main__":
    seed()
